  83	
  84	// Use exponential notation for small or very large numbers to avoid labels with too many characters
  85	const formatPositiveValue = (v: number): string =>
  86	  v === 0 || (0.001 <= v && v < 1e23) ? humanizeNumberSI(v).string : v.toExponential(1);
  87	
  88	const formatValue = (v: number): string => (v < 0 ? '-' : '') + formatPositiveValue(Math.abs(v));
  89	
  90	const valueFormatter = (units: string): ((v: number) => string) =>
  91	  ['ms', 's', 'bytes', 'Bps', 'pps'].includes(units)
  92	    ? (v: number) => formatNumber(String(v), undefined, units)
  93	    : formatValue;
  94	
  95	export const Error: React.FC<ErrorProps> = ({ error, title = 'An error occurred' }) => (
  96	  <Alert isInline title={title} variant="danger">
  97	    {_.get(error, 'json.error', error.message)}
