 113	const SpanControls: React.FC<SpanControlsProps> = React.memo(
 114	  ({ defaultSpanText, onChange, span, hasReducedResolution }) => {
 115	    const { t } = useTranslation(process.env.I18N_NAMESPACE);
 116	
 117	    const [isValid, setIsValid] = React.useState(true);
 118	    const [text, setText] = React.useState(formatPrometheusDuration(span));
 119	
 120	    const [isOpen, setIsOpen, , setClosed] = useBoolean(false);
 121	
 122	    React.useEffect(() => {
 123	      setText(formatPrometheusDuration(span));
 124	    }, [span]);
 125	
 126	    // eslint-disable-next-line react-hooks/exhaustive-deps
 127	    const debouncedOnChange = React.useCallback(_.debounce(onChange, 400), [onChange]);
 128	
 129	    const setSpan = (newText: string, isDebounced = false) => {
 130	      const newSpan = parsePrometheusDuration(newText);
 131	      const newIsValid = newSpan > 0;
 132	      setIsValid(newIsValid);
 133	      setText(newText);
 134	      if (newIsValid && newSpan !== span) {
 135	        const fn = isDebounced ? debouncedOnChange : onChange;
 136	        fn(newSpan);
 137	      }
 138	    };
 139	
 140	    const dropdownItems = spans.map((s) => (
 141	      <DropdownItem
 142	        className="query-browser__span-dropdown-item"
 143	        key={s}
 144	        onClick={() => setSpan(s, true)}
 145	      >
 146	        {s}
 147	      </DropdownItem>
 148	    ));
 149	
 150	    return (
 151	      <>
 152	        <InputGroup className="query-browser__span">
 153	          <InputGroupItem isFill>
 154	            <TextInput
 155	              aria-label={t('graph timespan')}
 156	              className="query-browser__span-text"
 157	              validated={isValid ? 'default' : 'error'}
 158	              onChange={(_event, v) => setSpan(v, true)}
 159	              type="text"
 160	              value={text}
 161	            />
 162	          </InputGroupItem>
 163	          <InputGroupItem>
 164	            <Dropdown
 165	              isOpen={isOpen}
 166	              onSelect={setClosed}
 167	              toggle={(toggleRef: React.Ref<MenuToggleElement>) => (
 168	                <MenuToggle
 169	                  ref={toggleRef}
 170	                  onClick={setIsOpen}
 171	                  isExpanded={isOpen}
