 178	            </Dropdown>
 179	          </InputGroupItem>
 180	        </InputGroup>
 181	        <Button
 182	          className="query-browser__inline-control"
 183	          onClick={() => setSpan(defaultSpanText)}
 184	          type="button"
 185	          variant="tertiary"
 186	        >
 187	          {t('Reset zoom')}
 188	        </Button>
 189	        {hasReducedResolution && (
 190	          <Alert
 191	            isInline
 192	            isPlain
 193	            className="query-browser__reduced-resolution"
 194	            title={t('Displaying with reduced resolution due to large dataset.')}
