 204	const TOOLTIP_MAX_ENTRIES = 20;
 205	const TOOLTIP_MAX_WIDTH = 400;
 206	const TOOLTIP_MAX_HEIGHT = 400;
 207	const TOOLTIP_MAX_LEFT_JUT_OUT = 85;
 208	const TOOLTIP_MAX_RIGHT_JUT_OUT = 45;
 209	
 210	type TooltipSeries = {
 211	  color: string;
 212	  labels: PrometheusLabels;
 213	  name: string;
 214	  total: number;
 215	  value: string;
 216	};
 217	
 218	// For performance, use this instead of PatternFly's ChartTooltip or Victory VictoryTooltip
 219	const Tooltip_: React.FC<TooltipProps> = ({ activePoints, center, height, style, width, x }) => {
 220	  const time = activePoints?.[0]?.x;
 221	
 222	  if (!_.isDate(time) || !_.isFinite(x)) {
 223	    return null;
 224	  }
 225	
 226	  // Don't show the tooltip if the cursor is too far from the active points (can happen when the
 227	  // graph's timespan includes a range with no data)
 228	  if (Math.abs(x - center.x) > width / 15) {
 229	    return null;
 230	  }
 231	
 232	  // Pick tooltip width and location (left or right of the cursor) to maximize its available space
 233	  const spaceOnLeft = x + TOOLTIP_MAX_LEFT_JUT_OUT;
 234	  const spaceOnRight = width - x + TOOLTIP_MAX_RIGHT_JUT_OUT;
 235	  const isOnLeft = spaceOnLeft > spaceOnRight;
 236	  const tooltipMaxWidth = Math.min(isOnLeft ? spaceOnLeft : spaceOnRight, TOOLTIP_MAX_WIDTH);
 237	
 238	  // Sort the entries in the tooltip from largest to smallest (to match the position of points in
 239	  // the graph) and limit to the maximum number we can display. There could be a large number of
 240	  // points, so we use a slightly less succinct approach to avoid sorting the whole list of points
 241	  // and to avoid processing points that won't fit in the tooltip.
 242	  const largestPoints: TooltipSeries[] = [];
 243	  activePoints.forEach(({ _y1, y }, i) => {
 244	    const total = _y1 ?? y;
 245	    if (
 246	      largestPoints.length < TOOLTIP_MAX_ENTRIES ||
 247	      largestPoints[TOOLTIP_MAX_ENTRIES - 1].total < total
 248	    ) {
 249	      const point = {
 250	        color: style[i]?.fill,
 251	        labels: style[i]?.labels,
 252	        name: style[i]?.name,
 253	        total,
 254	        value: valueFormatter(style[i]?.units)(y),
 255	      };
 256	      largestPoints.splice(
 257	        _.sortedIndexBy(largestPoints, point, (p) => -p.total),
 258	        0,
 259	        point,
 260	      );
 261	    }
 262	  });
 263	  const allSeries: TooltipSeries[] = largestPoints.slice(0, TOOLTIP_MAX_ENTRIES);
 264	
 265	  // For each series we are displaying in the tooltip, create a name based on its labels. We have
 266	  // limited space, so sort the labels to try to show the most useful first since later labels will
 267	  // likely be cut off. Sort first by the number of unique values for the label (prefer to show
 268	  // labels with more values because they are more helpful in identifying the series), then by the
 269	  // length of the label (prefer to show sorter labels because space is limited).
 270	  const allSeriesSorted: string[] = _.sortBy(
 271	    _.without(
 272	      _.uniq(_.flatMap(allSeries, (s) => (s.labels ? Object.keys(s.labels) : []))),
 273	      '__name__',
 274	    ),
 275	    [(k) => -_.uniq(allSeries.map((s) => s.labels[k])).length, (k) => k.length],
 276	  );
 277	  const getSeriesName = (series: TooltipSeries): string => {
 278	    if (_.isString(series.name)) {
 279	      return series.name;
 280	    }
 281	    if (_.isEmpty(series.labels)) {
 282	      return '{}';
 283	    }
 284	    const name = series.labels.__name__ ?? '';
 285	    const otherLabels = _.intersection(allSeriesSorted, Object.keys(series.labels));
 286	    return `${name}{${otherLabels.map((l) => `${l}=${series.labels[l]}`).join(',')}}`;
 287	  };
 288	
 289	  return (
 290	    <>
 291	      <VictoryPortal>
 292	        <foreignObject
 293	          height={TOOLTIP_MAX_HEIGHT}
 294	          width={tooltipMaxWidth}
 295	          x={isOnLeft ? x - tooltipMaxWidth : x}
 296	          y={center.y - TOOLTIP_MAX_HEIGHT / 2}
 297	        >
 298	          <div
 299	            className={classNames('query-browser__tooltip-wrap', {
 300	              'query-browser__tooltip-wrap--left': isOnLeft,
 301	            })}
 302	          >
 303	            <div className="query-browser__tooltip-arrow" />
 304	            <div className="query-browser__tooltip">
 305	              <div className="query-browser__tooltip-time">
 306	                {dateTimeFormatterWithSeconds.format(time)}
 307	              </div>
 308	              {allSeries.map((s, i) => (
 309	                <div className="query-browser__tooltip-series" key={i}>
 310	                  <div className="query-browser__series-btn" style={{ backgroundColor: s.color }} />
 311	                  <Truncate content={getSeriesName(s)} />
 312	                  <div className="query-browser__tooltip-value">{s.value}</div>
 313	                </div>
 314	              ))}
 315	            </div>
 316	          </div>
 317	        </foreignObject>
 318	      </VictoryPortal>
 319	      <line className="query-browser__tooltip-line" x1={x} x2={x} y1="0" y2={height} />
 320	    </>
 321	  );
 322	};
 323	const Tooltip = withFallback(Tooltip_);
 324	
 325	const graphContainer = (
 326	  // Set activateData to false to work around VictoryVoronoiContainer crash (see
 327	  // https://github.com/FormidableLabs/victory/issues/1314)
 328	  <ChartVoronoiContainer
 329	    activateData={false}
 330	    labelComponent={<Tooltip />}
 331	    labels={() => ' '}
 332	    mouseFollowTooltips={true}
 333	    voronoiDimension="x"
 334	    voronoiPadding={0}
 335	  />
 336	);
 337	
 338	const LegendContainer = ({ children }: { children?: React.ReactNode }) => {
 339	  // The first child should be a <rect> with a `width` prop giving the legend's content width
 340	  const width = children?.[0]?.[0]?.props?.width ?? '100%';
 341	  return (
 342	    <foreignObject height={75} width="100%" y={245}>
 343	      <div className="monitoring-dashboards__legend-wrap horizontal-scroll">
 344	        <svg width={width}>{children}</svg>
 345	      </div>
 346	    </foreignObject>
 347	  );
 348	};
 349	
 350	const Null = () => null;
 351	const nullComponent = <Null />;
 352	
 353	type GraphSeries = GraphDataPoint[] | null;
 354	
 355	const getXDomain = (endTime: number, span: number): AxisDomain => [endTime - span, endTime];
 356	
 357	const ONE_MINUTE = 60 * 1000;
 358	
 359	const Graph: React.FC<GraphProps> = React.memo(
 360	  ({
 361	    allSeries,
 362	    disabledSeries,
 363	    fixedXDomain,
 364	    formatSeriesTitle,
 365	    isStack,
 366	    showLegend,
 367	    span,
 368	    units,
 369	    width,
 370	  }) => {
 371	    const { t } = useTranslation(process.env.I18N_NAMESPACE);
 372	
 373	    const data: GraphSeries[] = [];
 374	    const tooltipSeriesNames: string[] = [];
 375	    const tooltipSeriesLabels: PrometheusLabels[] = [];
 376	    const legendData: { name: string }[] = [];
 377	
 378	    const [xDomain, setXDomain] = React.useState(fixedXDomain || getXDomain(Date.now(), span));
 379	
 380	    // Only update X-axis if the time range (fixedXDomain or span) or graph data (allSeries) change
 381	    React.useEffect(() => {
 382	      setXDomain(fixedXDomain || getXDomain(Date.now(), span));
 383	    }, [allSeries, span, fixedXDomain]);
 384	
 385	    const domain = { x: xDomain, y: undefined };
 386	
 387	    _.each(allSeries, (series, i) => {
 388	      _.each(series, ([metric, values]) => {
 389	        // Ignore any disabled series
 390	        data.push(_.some(disabledSeries?.[i], (s) => _.isEqual(s, metric)) ? null : values);
 391	        if (formatSeriesTitle) {
 392	          const name = formatSeriesTitle(metric, i);
 393	          legendData.push({ name });
 394	          tooltipSeriesNames.push(name);
 395	        } else {
 396	          tooltipSeriesLabels.push(metric);
 397	        }
 398	      });
 399	    });
 400	
 401	    if (!data.some(Array.isArray)) {
 402	      return <GraphEmpty />;
 403	    }
 404	
 405	    let yTickFormat = valueFormatter(units);
 406	
 407	    if (isStack) {
 408	      // Specify Y axis range if all values are zero, but otherwise let Chart set it automatically
 409	      const isAllZero = _.every(allSeries, (series) =>
 410	        _.every(series, ([, values]) => _.every(values, { y: 0 })),
 411	      );
 412	      if (isAllZero) {
 413	        domain.y = [0, 1];
 414	      }
 415	    } else {
 416	      // Set a reasonable Y-axis range based on the min and max values in the data
 417	      const findMin = (series: GraphSeries): GraphDataPoint => _.minBy(series, 'y');
 418	      const findMax = (series: GraphSeries): GraphDataPoint => _.maxBy(series, 'y');
 419	      let minY: number = findMin(data.map(findMin))?.y ?? 0;
 420	      let maxY: number = findMax(data.map(findMax))?.y ?? 0;
 421	      if (minY === 0 && maxY === 0) {
 422	        minY = 0;
 423	        maxY = 1;
 424	      } else if (minY > 0 && maxY > 0) {
 425	        minY = 0;
 426	      } else if (minY < 0 && maxY < 0) {
 427	        maxY = 0;
 428	      }
 429	
 430	      domain.y = [minY, maxY];
 431	
 432	      if (Math.abs(maxY - minY) < 0.005) {
 433	        yTickFormat = (v: number) => (v === 0 ? '0' : v.toExponential(1));
 434	      }
 435	    }
 436	
 437	    const xAxisTickCount = Math.round(width / 100);
 438	    const xAxisTickShowSeconds = span < xAxisTickCount * ONE_MINUTE;
 439	    const xAxisTickFormat = (d) => {
 440	      if (span > parsePrometheusDuration('1d')) {
 441	        // Add a newline between the date and time so tick labels don't overlap.
 442	        return `${dateFormatterNoYear.format(d)}\n${timeFormatter.format(d)}`;
 443	      }
 444	      if (xAxisTickShowSeconds) {
 445	        return timeFormatterWithSeconds.format(d);
 446	      }
 447	      return timeFormatter.format(d);
 448	    };
 449	
 450	    const GroupComponent = isStack ? ChartStack : ChartGroup;
 451	    const ChartComponent = isStack ? ChartArea : ChartLine;
 452	
 453	    return (
 454	      <Chart
 455	        containerComponent={graphContainer}
 456	        ariaTitle={t('query browser chart')}
 457	        domain={domain}
 458	        domainPadding={{ y: 1 }}
 459	        height={200}
 460	        scale={{ x: 'time', y: 'linear' }}
 461	        theme={queryBrowserTheme}
 462	        width={width}
 463	      >
 464	        <ChartAxis tickCount={xAxisTickCount} tickFormat={xAxisTickFormat} />
 465	        <ChartAxis
 466	          crossAxis={false}
 467	          dependentAxis
 468	          tickComponent={nullComponent}
 469	          tickCount={6}
 470	          tickFormat={yTickFormat}
 471	        />
 472	        <GroupComponent>
 473	          {data.map((values, i) => {
 474	            if (values === null) {
 475	              return null;
 476	            }
 477	            const color = colors[i % colors.length];
 478	            const style = {
 479	              data: { [isStack ? 'fill' : 'stroke']: color },
 480	              labels: {
 481	                fill: color,
 482	                labels: tooltipSeriesLabels[i],
 483	                name: tooltipSeriesNames[i],
 484	                units,
 485	              },
 486	            };
 487	            return (
 488	              // We need to use the `name` prop to prevent an error in VictorySharedEvents when
 489	              // dynamically removing and then adding back data series
 490	              <ChartComponent
 491	                data={values}
 492	                groupComponent={<g />}
 493	                key={i}
 494	                name={`series-${i}`}
 495	                style={style}
 496	              />
 497	            );
 498	          })}
 499	        </GroupComponent>
 500	        {showLegend && !_.isEmpty(legendData) && (
 501	          <ChartLegend
 502	            data={legendData}
 503	            groupComponent={<LegendContainer />}
 504	            gutter={30}
 505	            itemsPerRow={4}
 506	            orientation="vertical"
 507	            style={{
 508	              labels: { fontSize: 11, fill: 'var(--pf-t--global--text--color--regular)' },
 509	            }}
 510	            symbolSpacer={4}
 511	          />
 512	        )}
 513	      </Chart>
 514	    );
 515	  },
 516	);
 517	
 518	const formatSeriesValues = (
 519	  values: PrometheusValue[],
 520	  samples: number,
 521	  span: number,
 522	  defaultEmptyValue: 0 | null,
 523	): GraphDataPoint[] => {
 524	  const newValues = _.map(values, (v) => {
 525	    const y = Number(v[1]);
 526	    return {
 527	      x: new Date(v[0] * 1000),
 528	      y: Number.isNaN(y) ? defaultEmptyValue : y,
 529	    };
 530	  });
 531	
 532	  // The data may have missing values, so we fill those gaps with nulls so that the graph correctly
 533	  // shows the missing values as gaps in the line
 534	  const start = Number(_.get(newValues, '[0].x'));
 535	  const end = Number(_.get(_.last(newValues), 'x'));
 536	  const step = span / samples;
 537	  _.range(start, end, step).forEach((t, i) => {
 538	    const x = new Date(t);
 539	    if (_.get(newValues, [i, 'x']) > x) {
 540	      newValues.splice(i, 0, { x, y: null });
 541	    }
 542	  });
 543	
 544	  return newValues;
 545	};
 546	
 547	// Try to limit the graph to this number of data points
 548	const maxDataPointsSoft = 6000;
 549	
 550	// If we have more than this number of data points, do not render the graph
 551	const maxDataPointsHard = 10000;
 552	
 553	// Min and max number of data samples per data series
 554	const minSamples = 10;
 555	const maxSamples = 300;
 556	
 557	// Fall back to a line chart for performance if there are too many series
 558	const maxStacks = 50;
 559	
 560	// We don't want to refresh all the graph data for just a small adjustment in the number of samples,
 561	// so don't update unless the number of samples would change by at least this proportion
 562	const samplesLeeway = 0.2;
 563	
 564	// Minimum step (milliseconds between data samples) because tiny steps reduce performance for almost
 565	// no benefit
 566	const minStep = 5 * 1000;
 567	
 568	// Don't allow zooming to less than this number of milliseconds
 569	const minSpan = 30 * 1000;
 570	
 571	// Don't poll more often than this number of milliseconds
 572	const minPollInterval = 10 * 1000;
 573	
 574	const ZoomableGraph: React.FC<ZoomableGraphProps> = ({
 575	  allSeries,
 576	  disabledSeries,
 577	  fixedXDomain,
 578	  formatSeriesTitle,
 579	  isStack,
 580	  onZoom,
 581	  showLegend,
 582	  span,
 583	  units,
 584	  width,
 585	}) => {
 586	  const [isZooming, setIsZooming] = React.useState(false);
 587	  const [x1, setX1] = React.useState(0);
 588	  const [x2, setX2] = React.useState(0);
 589	
 590	  const onKeyDown = (e: React.KeyboardEvent) => {
 591	    if (e.key === 'Escape') {
 592	      e.preventDefault();
 593	      setIsZooming(false);
 594	    }
 595	  };
 596	
 597	  const onMouseDown = (e: React.MouseEvent) => {
 598	    setIsZooming(true);
 599	    const x = e.clientX - e.currentTarget.getBoundingClientRect().left;
 600	    setX1(x);
 601	    setX2(x);
 602	  };
 603	
 604	  const onMouseMove = (e: React.MouseEvent) => {
 605	    setX2(e.clientX - e.currentTarget.getBoundingClientRect().left);
 606	  };
 607	
 608	  const onMouseUp = (e: React.MouseEvent) => {
 609	    setIsZooming(false);
 610	
 611	    const xMin = Math.min(x1, x2);
 612	    const xMax = Math.max(x1, x2);
 613	
 614	    // Don't do anything if a range was not selected (don't zoom if you just click the graph)
 615	    if (xMax === xMin) {
 616	      return;
 617	    }
 618	
 619	    const zoomWidth = e.currentTarget.getBoundingClientRect().width;
 620	    const oldFrom = _.get(fixedXDomain, '[0]', Date.now() - span);
 621	    let from = oldFrom + (span * xMin) / zoomWidth;
 622	    let to = oldFrom + (span * xMax) / zoomWidth;
 623	    let newSpan = to - from;
 624	
 625	    if (newSpan < minSpan) {
 626	      newSpan = minSpan;
