 746	    setGraphData(null);
 747	    if (fixedEndTime) {
 748	      setXDomain(getXDomain(fixedEndTime, span));
 749	    }
 750	  }, [fixedEndTime, span]);
 751	
 752	  React.useEffect(() => {
 753	    if (!fixedEndTime) {
 754	      setXDomain(undefined);
 755	    }
 756	  }, [fixedEndTime]);
 757	
 758	  // Clear any existing series data when the namespace is changed
 759	  React.useEffect(() => {
 760	    dispatch(queryBrowserDeleteAllSeries());
 761	  }, [dispatch, activeNamespace]);
 762	
 763	  const tick = () => {
 764	    if (hideGraphs) {
 765	      return undefined;
 766	    }
 767	
 768	    // Define this once for all queries so that they have exactly the same time range and X values
 769	    const now = Date.now();
 770	    const timeRanges = getTimeRanges(span, endTime || now);
 771	
 772	    const queryPromises = _.map(queries, (query) => {
 773	      if (_.isEmpty(query)) {
 774	        return Promise.resolve([]);
 775	      } else {
 776	        const promiseMap: Promise<PrometheusResponse>[] = _.map(
 777	          timeRanges,
 778	          (timeRange: TimeRange) =>
 779	            safeFetch(
 780	              getPrometheusURL(
 781	                {
 782	                  endpoint: PrometheusEndpoint.QUERY_RANGE,
 783	                  endTime: timeRange.endTime,
 784	                  namespace: perspective === 'dev' ? activeNamespace : '',
 785	                  query,
 786	                  samples: Math.ceil(samples / timeRanges.length),
 787	                  timeout: '60s',
 788	                  timespan: timeRange.duration - 1,
 789	                },
 790	                perspective,
 791	                customDataSource?.basePath,
 792	              ),
 793	            ),
 794	        );
 795	        return Promise.all(promiseMap).then((responses) => {
 796	          const results: PrometheusResult[][] = _.map(responses, 'data.result');
 797	          const combinedQueries = results.reduce(
 798	            (accumulator: PrometheusResult[], response: PrometheusResult[]): PrometheusResult[] => {
 799	              response.forEach((metricResult) => {
 800	                const index = accumulator.findIndex(
 801	                  (item) => JSON.stringify(item.metric) === JSON.stringify(metricResult.metric),
 802	                );
 803	                if (index === -1) {
 804	                  accumulator.push(metricResult);
 805	                } else {
 806	                  accumulator[index].values = accumulator[index].values.concat(metricResult.values);
 807	                }
 808	              });
 809	              return accumulator;
 810	            },
 811	            [],
 812	          );
 813	          // Recombine into the original query to allow for the redux store and the things using
 814	          // it (query duplication, ect) to be able to work. Grab the heading of the first response
 815	          // for the status and structure of the response
 816	          const queryResponse = responses.at(0);
 817	          if (!queryResponse) {
 818	            return [];
 819	          }
 820	          queryResponse.data.result = combinedQueries;
 821	          return queryResponse;
 822	        });
 823	      }
 824	    });
 825	
 826	    return Promise.all(queryPromises)
 827	      .then((responses: PrometheusResponse[]) => {
 828	        const newResults = _.map(responses, 'data.result');
 829	        const numDataPoints = _.sumBy(newResults, (r) => _.sumBy(r, 'values.length'));
 830	
 831	        if (numDataPoints > maxDataPointsHard && samples === minSamples) {
 832	          setIsDatasetTooBig(true);
 833	          return;
 834	        }
 835	        setIsDatasetTooBig(false);
 836	
 837	        const newSamples = _.clamp(
 838	          Math.floor((samples * maxDataPointsSoft) / numDataPoints),
 839	          minSamples,
 840	          maxSamplesForSpan,
 841	        );
 842	
 843	        // Change `samples` if either
 844	        //   - It will change by a proportion greater than `samplesLeeway`
 845	        //   - It will change to the upper or lower limit of its allowed range
 846	        if (
 847	          Math.abs(newSamples - samples) / samples > samplesLeeway ||
 848	          (newSamples !== samples &&
 849	            (newSamples === maxSamplesForSpan || newSamples === minSamples))
 850	        ) {
 851	          setSamples(newSamples);
 852	        } else {
 853	          const newGraphData = _.map(
 854	            newResults,
 855	            (result: PrometheusResult[], queryIndex: number) => {
 856	              return _.map(result, ({ metric, values }): Series => {
 857	                // If filterLabels is specified, ignore all series that don't match
 858	                if (_.some(filterLabels, (v, k) => _.has(metric, k) && metric[k] !== v)) {
 859	                  return [];
 860	                } else {
 861	                  let defaultEmptyValue = null;
 862	                  if (isStack && _.some(values, (value) => Number.isNaN(Number(value[1])))) {
 863	                    // eslint-disable-next-line no-console
 864	                    console.warn(
 865	                      'Invalid response values for stacked graph converted to 0 for query: ',
 866	                      queries[queryIndex],
 867	                    );
 868	                    defaultEmptyValue = 0;
 869	                  }
 870	                  return [metric, formatSeriesValues(values, samples, span, defaultEmptyValue)];
 871	                }
 872	              });
 873	            },
 874	          );
 875	          setGraphData(newGraphData);
 876	          onDataChange?.(newGraphData);
 877	
 878	          _.each(newResults, (r, i) =>
 879	            dispatch(queryBrowserPatchQuery(i, { series: r ? _.map(r, 'metric') : undefined })),
 880	          );
 881	          setUpdating(false);
 882	        }
 883	        setError(undefined);
 884	      })
 885	      .catch((err) => {
 886	        if (err.name !== 'AbortError') {
 887	          // eslint-disable-next-line no-console
 888	          console.log(err);
 889	          setError(err);
 890	          setUpdating(false);
 891	        }
 892	      });
 893	  };
 894	
 895	  // Don't poll if an end time was set (because the latest data is not displayed) or if the graph is
 896	  // hidden. Otherwise use a polling interval relative to the graph's timespan.
 897	  let delay: number;
 898	  if (endTime || hideGraphs || tickInterval === null) {
 899	    delay = null;
 900	  } else if (tickInterval > 0) {
 901	    delay = tickInterval;
 902	  } else {
 903	    delay = Math.max(span / 120, minPollInterval);
 904	  }
 905	
 906	  const queriesKey = _.reject(queries, _.isEmpty).join();
 907	  usePoll(
 908	    tick,
 909	    delay,
 910	    endTime,
 911	    filterLabels,
 912	    activeNamespace,
 913	    queriesKey,
 914	    samples,
 915	    span,
 916	    lastRequestTime,
 917	  );
 918	
 919	  React.useLayoutEffect(
 920	    () => setUpdating(true),
 921	    [endTime, activeNamespace, queriesKey, samples, span],
 922	  );
 923	
 924	  const onSpanChange = React.useCallback(
 925	    (newSpan: number) => {
 926	      setGraphData(null);
 927	      setXDomain(undefined);
 928	      setSpan(newSpan);
 929	      dispatch(queryBrowserSetTimespan(newSpan));
 930	      setSamples(defaultSamples || getMaxSamplesForSpan(newSpan));
 931	    },
 932	    [defaultSamples, dispatch],
 933	  );
 934	
 935	  const isRangeVector = _.get(error, 'json.error', '').match(
 936	    /invalid expression type "range vector"/,
 937	  );
 938	
 939	  if (hideGraphs) {
 940	    // Still render the graph containers so that `width` continues to be tracked while the graph is
 941	    // hidden. This ensures we can render at the correct width when the graph is shown again.
 942	    return (
 943	      <>
 944	        {error && !isRangeVector && <Error error={error} />}
 945	        <div className="query-browser__wrapper query-browser__wrapper--hidden">
 946	          <div className="graph-wrapper graph-wrapper--query-browser">
 947	            <div ref={containerRef} style={{ width: '100%' }}></div>
 948	          </div>
 949	        </div>
 950	      </>
 951	    );
 952	  }
 953	
 954	  if (isRangeVector) {
 955	    return (
 956	      <GraphEmptyState title={t('Ungraphable results')}>
 957	        {t(
 958	          'Query results include range vectors, which cannot be graphed. Try adding a function to transform the data.',
 959	        )}
 960	      </GraphEmptyState>
 961	    );
 962	  }
 963	
 964	  if (error?.json?.error?.match(/invalid expression type "string"/)) {
 965	    return (
 966	      <GraphEmptyState title={t('Ungraphable results')}>
 967	        {t('Query result is a string, which cannot be graphed.')}
 968	      </GraphEmptyState>
 969	    );
 970	  }
 971	
 972	  if (isDatasetTooBig) {
 973	    return (
 974	      <GraphEmptyState title={t('Ungraphable results')}>
 975	        {t('The resulting dataset is too large to graph.')}
 976	      </GraphEmptyState>
 977	    );
 978	  }
 979	
 980	  const zoomableGraphOnZoom = (from: number, to: number) => {
 981	    setGraphData(null);
 982	    setXDomain([from, to]);
 983	    setSpan(to - from);
 984	    setSamples(defaultSamples || getMaxSamplesForSpan(to - from));
 985	    onZoom?.(from, to);
 986	  };
 987	
 988	  const isGraphDataEmpty = !graphData || graphData.every((d) => d.length === 0);
 989	  const hasReducedResolution = !isGraphDataEmpty && samples < maxSamplesForSpan && !updating;
 990	
 991	  return (
 992	    <div
 993	      className={classNames('query-browser__wrapper', {
 994	        'graph-empty-state': isGraphDataEmpty,
 995	        'graph-empty-state__loaded': isGraphDataEmpty && !updating,
 996	      })}
 997	    >
 998	      {hideControls ? (
 999	        <>{updating && <Loading />}</>
1000	      ) : (
1001	        <div className="query-browser__controls">
1002	          <div className="query-browser__controls--left">
1003	            <SpanControls
1004	              defaultSpanText={defaultSpanText}
1005	              onChange={onSpanChange}
1006	              span={span}
1007	              hasReducedResolution={hasReducedResolution}
1008	            />
1009	            {updating && <Loading />}
1010	          </div>
1011	          <div className="query-browser__controls--right">
1012	            {GraphLink && <GraphLink />}
1013	            {canStack && showStackedControl && (
1014	              <Checkbox
1015	                id="stacked"
1016	                isChecked={isStacked}
1017	                data-checked-state={isStacked}
1018	                label={t('Stacked')}
1019	                onChange={(_e, v) => (typeof _e === 'boolean' ? setIsStacked(_e) : setIsStacked(v))}
1020	              />
1021	            )}
1022	          </div>
1023	        </div>
1024	      )}
1025	      <div
1026	        className={classNames('graph-wrapper graph-wrapper--query-browser', {
1027	          'graph-wrapper--query-browser--with-legend': showLegend && !!formatSeriesTitle,
1028	        })}
1029	      >
1030	        <div ref={containerRef} style={{ width: '100%' }}>
1031	          {error && <Error error={error} />}
1032	          {isGraphDataEmpty && !updating && <GraphEmpty />}
1033	          {!isGraphDataEmpty && width > 0 && (
1034	            <>
1035	              {disableZoom ? (
1036	                <Graph
1037	                  allSeries={graphData}
1038	                  disabledSeries={disabledSeries}
1039	                  fixedXDomain={xDomain}
1040	                  formatSeriesTitle={formatSeriesTitle}
1041	                  isStack={canStack && isStacked}
1042	                  showLegend={showLegend}
1043	                  span={span}
1044	                  units={units}
1045	                  width={width}
1046	                />
1047	              ) : (
1048	                <ZoomableGraph
1049	                  allSeries={graphData}
1050	                  disabledSeries={disabledSeries}
1051	                  fixedXDomain={xDomain}
1052	                  formatSeriesTitle={formatSeriesTitle}
1053	                  isStack={canStack && isStacked}
1054	                  onZoom={zoomableGraphOnZoom}
1055	                  showLegend={showLegend}
1056	                  span={span}
1057	                  units={units}
1058	                  width={width}
1059	                />
1060	              )}
1061	            </>
1062	          )}
1063	        </div>
1064	      </div>
1065	    </div>
1066	  );
1067	};
