 597	  const onMouseDown = (e: React.MouseEvent) => {
 598	    setIsZooming(true);
 599	    const x = e.clientX - e.currentTarget.getBoundingClientRect().left;
 600	    setX1(x);
 601	    setX2(x);
 602	  };
 603	
 604	  const onMouseMove = (e: React.MouseEvent) => {
 605	    setX2(e.clientX - e.currentTarget.getBoundingClientRect().left);
 606	  };
