 622	    let to = oldFrom + (span * xMax) / zoomWidth;
 623	    let newSpan = to - from;
 624	
 625	    if (newSpan < minSpan) {
 626	      newSpan = minSpan;
 627	      const middle = (from + to) / 2;
 628	      from = middle - newSpan / 2;
 629	      to = middle + newSpan / 2;
 630	    }
