 639	  return (
 640	    <div className="query-browser__zoom" {...handlers}>
 641	      {isZooming && (
 642	        <div
 643	          className="query-browser__zoom-overlay"
 644	          style={{ left: Math.min(x1, x2), width: Math.abs(x1 - x2) }}
 645	        />
 646	      )}
