 651	        formatSeriesTitle={formatSeriesTitle}
 652	        isStack={isStack}
 653	        showLegend={showLegend}
 654	        span={span}
 655	        units={units}
 656	        width={width}
 657	      />
 658	    </div>
 659	  );
 660	};
