 780	              getPrometheusURL(
 781	                {
 782	                  endpoint: PrometheusEndpoint.QUERY_RANGE,
 783	                  endTime: timeRange.endTime,
 784	                  namespace: perspective === 'dev' ? activeNamespace : '',
