 865	                      'Invalid response values for stacked graph converted to 0 for query: ',
 866	                      queries[queryIndex],
 867	                    );
 868	                    defaultEmptyValue = 0;
 869	                  }
 870	                  return [metric, formatSeriesValues(values, samples, span, defaultEmptyValue)];
 871	                }
