 217	// For performance, use this instead of PatternFly's ChartTooltip or Victory VictoryTooltip
 218	const Tooltip_: React.FC<TooltipProps> = ({ activePoints, center, height, style, width, x }) => {
 219	  const time = activePoints?.[0]?.x;
 220	
 221	  if (!_.isDate(time) || !_.isFinite(x)) {
 222	    return null;
 223	  }
 224	
 225	  // Don't show the tooltip if the cursor is too far from the active points (can happen when the
 226	  // graph's timespan includes a range with no data)
 227	  if (Math.abs(x - center.x) > width / 15) {
 228	    return null;
 229	  }
 230	
 231	  // Pick tooltip width and location (left or right of the cursor) to maximize its available space
 232	  const spaceOnLeft = x + TOOLTIP_MAX_LEFT_JUT_OUT;
 233	  const spaceOnRight = width - x + TOOLTIP_MAX_RIGHT_JUT_OUT;
 234	  const isOnLeft = spaceOnLeft > spaceOnRight;
 235	  const tooltipMaxWidth = Math.min(isOnLeft ? spaceOnLeft : spaceOnRight, TOOLTIP_MAX_WIDTH);
 236	
 237	  // Sort the entries in the tooltip from largest to smallest (to match the position of points in
 238	  // the graph) and limit to the maximum number we can display. There could be a large number of
 239	  // points, so we use a slightly less succinct approach to avoid sorting the whole list of points
 240	  // and to avoid processing points that won't fit in the tooltip.
 241	  const largestPoints: TooltipSeries[] = [];
 242	  activePoints.forEach(({ _y1, y }, i) => {
 243	    const total = _y1 ?? y;
 244	    if (
 245	      largestPoints.length < TOOLTIP_MAX_ENTRIES ||
 246	      largestPoints[TOOLTIP_MAX_ENTRIES - 1].total < total
 247	    ) {
 248	      const point = {
 249	        color: style[i]?.fill,
 250	        labels: style[i]?.labels,
 251	        name: style[i]?.name,
 252	        total,
 253	        value: valueFormatter(style[i]?.units)(y),
 254	      };
 255	      largestPoints.splice(
 256	        _.sortedIndexBy(largestPoints, point, (p) => -p.total),
 257	        0,
 258	        point,
 259	      );
 260	    }
 261	  });
 262	  const allSeries: TooltipSeries[] = largestPoints.slice(0, TOOLTIP_MAX_ENTRIES);
 263	
 264	  // For each series we are displaying in the tooltip, create a name based on its labels. We have
 265	  // limited space, so sort the labels to try to show the most useful first since later labels will
 266	  // likely be cut off. Sort first by the number of unique values for the label (prefer to show
 267	  // labels with more values because they are more helpful in identifying the series), then by the
 268	  // length of the label (prefer to show sorter labels because space is limited).
 269	  const allSeriesSorted: string[] = _.sortBy(
 270	    _.without(
 271	      _.uniq(_.flatMap(allSeries, (s) => (s.labels ? Object.keys(s.labels) : []))),
 272	      '__name__',
 273	    ),
 274	    [(k) => -_.uniq(allSeries.map((s) => s.labels[k])).length, (k) => k.length],
 275	  );
 276	  const getSeriesName = (series: TooltipSeries): string => {
 277	    if (_.isString(series.name)) {
 278	      return series.name;
 279	    }
 280	    if (_.isEmpty(series.labels)) {
 281	      return '{}';
 282	    }
 283	    const name = series.labels.__name__ ?? '';
 284	    const otherLabels = _.intersection(allSeriesSorted, Object.keys(series.labels));
 285	    return `${name}{${otherLabels.map((l) => `${l}=${series.labels[l]}`).join(',')}}`;
 286	  };
 287	
 288	  return (
 289	    <>
 290	      <VictoryPortal>
 291	        <foreignObject
 292	          height={TOOLTIP_MAX_HEIGHT}
 293	          width={tooltipMaxWidth}
 294	          x={isOnLeft ? x - tooltipMaxWidth : x}
 295	          y={center.y - TOOLTIP_MAX_HEIGHT / 2}
