 531	  // The data may have missing values, so we fill those gaps with nulls so that the graph correctly
 532	  // shows the missing values as gaps in the line
 533	  const start = Number(_.get(newValues, '[0].x'));
 534	  const end = Number(_.get(_.last(newValues), 'x'));
 535	  const step = span / samples;
 536	  _.range(start, end, step).forEach((t, i) => {
 537	    const x = new Date(t);
