 573	const ZoomableGraph: React.FC<ZoomableGraphProps> = ({
 574	  allSeries,
 575	  disabledSeries,
 576	  fixedXDomain,
 577	  formatSeriesTitle,
 578	  isStack,
 579	  onZoom,
 580	  showLegend,
 581	  span,
 582	  units,
 583	  width,
