 793	        );
 794	        return Promise.all(promiseMap).then((responses) => {
 795	          const results: PrometheusResult[][] = _.map(responses, 'data.result');
 796	          const combinedQueries = results.reduce(
 797	            (accumulator: PrometheusResult[], response: PrometheusResult[]): PrometheusResult[] => {
 798	              response.forEach((metricResult) => {
 799	                const index = accumulator.findIndex(
 800	                  (item) => JSON.stringify(item.metric) === JSON.stringify(metricResult.metric),
 801	                );
 802	                if (index === -1) {
 803	                  accumulator.push(metricResult);
 804	                } else {
 805	                  accumulator[index].values = accumulator[index].values.concat(metricResult.values);
 806	                }
 807	              });
 808	              return accumulator;
 809	            },
 810	            [],
 811	          );
