 231	  // Pick tooltip width and location (left or right of the cursor) to maximize its available space
 232	  const spaceOnLeft = x + TOOLTIP_MAX_LEFT_JUT_OUT;
 233	  const spaceOnRight = width - x + TOOLTIP_MAX_RIGHT_JUT_OUT;
 234	  const isOnLeft = spaceOnLeft > spaceOnRight;
 235	  const tooltipMaxWidth = Math.min(isOnLeft ? spaceOnLeft : spaceOnRight, TOOLTIP_MAX_WIDTH);
 236	
 237	  // Sort the entries in the tooltip from largest to smallest (to match the position of points in
 238	  // the graph) and limit to the maximum number we can display. There could be a large number of
 239	  // points, so we use a slightly less succinct approach to avoid sorting the whole list of points
 240	  // and to avoid processing points that won't fit in the tooltip.
 241	  const largestPoints: TooltipSeries[] = [];
 242	  activePoints.forEach(({ _y1, y }, i) => {
 243	    const total = _y1 ?? y;
 244	    if (
 245	      largestPoints.length < TOOLTIP_MAX_ENTRIES ||
 246	      largestPoints[TOOLTIP_MAX_ENTRIES - 1].total < total
 247	    ) {
 248	      const point = {
 249	        color: style[i]?.fill,
 250	        labels: style[i]?.labels,
 251	        name: style[i]?.name,
 252	        total,
 253	        value: valueFormatter(style[i]?.units)(y),
 254	      };
 255	      largestPoints.splice(
 256	        _.sortedIndexBy(largestPoints, point, (p) => -p.total),
 257	        0,
 258	        point,
 259	      );
 260	    }
