 267	  // labels with more values because they are more helpful in identifying the series), then by the
 268	  // length of the label (prefer to show sorter labels because space is limited).
 269	  const allSeriesSorted: string[] = _.sortBy(
 270	    _.without(
 271	      _.uniq(_.flatMap(allSeries, (s) => (s.labels ? Object.keys(s.labels) : []))),
 272	      '__name__',
 273	    ),
 274	    [(k) => -_.uniq(allSeries.map((s) => s.labels[k])).length, (k) => k.length],
