 666	
 667	const getMaxSamplesForSpan = (span: number) =>
 668	  _.clamp(Math.round(span / minStep), minSamples, maxSamples);
 669	
 670	const QueryBrowser_: React.FC<QueryBrowserProps> = ({
 671	  customDataSource,
 672	  defaultSamples,
 673	  defaultTimespan = parsePrometheusDuration('30m'),
 674	  disabledSeries,
 675	  disableZoom,
 676	  filterLabels,
 677	  fixedEndTime,
 678	  formatSeriesTitle,
 679	  GraphLink,
 680	  hideControls,
 681	  isStack = false,
 682	  onZoom,
 683	  pollInterval,
 684	  queries,
 685	  showLegend,
 686	  showStackedControl = false,
 687	  timespan,
 688	  units,
