 692	  const { perspective } = usePerspective();
 693	
 694	  const hideGraphs = useSelector(
 695	    (state: MonitoringState) => !!getLegacyObserveState(perspective, state)?.get('hideGraphs'),
 696	  );
 697	  const tickInterval = useSelector(
 698	    (state: MonitoringState) =>
 699	      pollInterval ??
 700	      getLegacyObserveState(perspective, state)?.getIn(['queryBrowser', 'pollInterval']),
 701	  );
 702	  const lastRequestTime = useSelector((state: MonitoringState) =>
 703	    getLegacyObserveState(perspective, state)?.getIn(['queryBrowser', 'lastRequestTime']),
 704	  );
 705	
 706	  const dispatch = useDispatch();
 707	
 708	  // For the default time span, use the first of the suggested span options that is at least as long
 709	  // as defaultTimespan
 710	  const defaultSpanText = spans.find((s) => parsePrometheusDuration(s) >= defaultTimespan);
 711	  // If we have both `timespan` and `defaultTimespan`, `timespan` takes precedence
 712	  const [span, setSpan] = React.useState(timespan || parsePrometheusDuration(defaultSpanText));
