 724	  const [containerRef, width] = useRefWidth();
 725	
 726	  const endTime = xDomain?.[1];
 727	
 728	  const safeFetch = useSafeFetch();
 729	
 730	  const [isStacked, setIsStacked] = React.useState(isStack);
 731	
 732	  const canStack = _.sumBy(graphData, 'length') <= maxStacks;
 733	
 734	  const [activeNamespace] = useActiveNamespace();
 735	
 736	  // If provided, `timespan` overrides any existing span setting
 737	  React.useEffect(() => {
 738	    if (timespan) {
 739	      setSpan(timespan);
 740	      setSamples(defaultSamples || getMaxSamplesForSpan(timespan));
 741	    }
 742	  }, [defaultSamples, timespan]);
 743	
 744	  React.useEffect(() => {
