 767	    // Define this once for all queries so that they have exactly the same time range and X values
 768	    const now = Date.now();
 769	    const timeRanges = getTimeRanges(span, endTime || now);
 770	
 771	    const queryPromises = _.map(queries, (query) => {
 772	      if (_.isEmpty(query)) {
