 776	          timeRanges,
 777	          (timeRange: TimeRange) =>
 778	            safeFetch(
 779	              getPrometheusURL(
 780	                {
 781	                  endpoint: PrometheusEndpoint.QUERY_RANGE,
 782	                  endTime: timeRange.endTime,
 783	                  namespace: perspective === 'dev' ? activeNamespace : '',
