 818	          }
 819	          queryResponse.data.result = combinedQueries;
 820	          return queryResponse;
 821	        });
 822	      }
 823	    });
 824	
 825	    return Promise.all(queryPromises)
 826	      .then((responses: PrometheusResponse[]) => {
 827	        const newResults = _.map(responses, 'data.result');
