 854	            (result: PrometheusResult[], queryIndex: number) => {
 855	              return _.map(result, ({ metric, values }): Series => {
 856	                // If filterLabels is specified, ignore all series that don't match
 857	                if (_.some(filterLabels, (v, k) => _.has(metric, k) && metric[k] !== v)) {
 858	                  return [];
 859	                } else {
 860	                  let defaultEmptyValue = null;
 861	                  if (isStack && _.some(values, (value) => Number.isNaN(Number(value[1])))) {
 862	                    // eslint-disable-next-line no-console
 863	                    console.warn(
 864	                      'Invalid response values for stacked graph converted to 0 for query: ',
 865	                      queries[queryIndex],
 866	                    );
 867	                    defaultEmptyValue = 0;
 868	                  }
 869	                  return [metric, formatSeriesValues(values, samples, span, defaultEmptyValue)];
 870	                }
 871	              });
 872	            },
 873	          );
 874	          setGraphData(newGraphData);
 875	          onDataChange?.(newGraphData);
 876	
 877	          _.each(newResults, (r, i) =>
 878	            dispatch(queryBrowserPatchQuery(i, { series: r ? _.map(r, 'metric') : undefined })),
 879	          );
 880	          setUpdating(false);
 881	        }
 882	        setError(undefined);
 883	      })
 884	      .catch((err) => {
 885	        if (err.name !== 'AbortError') {
 886	          // eslint-disable-next-line no-console
 887	          console.log(err);
 888	          setError(err);
 889	          setUpdating(false);
 890	        }
 891	      });
 892	  };
 893	
 894	  // Don't poll if an end time was set (because the latest data is not displayed) or if the graph is
 895	  // hidden. Otherwise use a polling interval relative to the graph's timespan.
 896	  let delay: number;
 897	  if (endTime || hideGraphs || tickInterval === null) {
 898	    delay = null;
 899	  } else if (tickInterval > 0) {
 900	    delay = tickInterval;
 901	  } else {
 902	    delay = Math.max(span / 120, minPollInterval);
 903	  }
 904	
 905	  const queriesKey = _.reject(queries, _.isEmpty).join();
 906	  usePoll(
 907	    tick,
 908	    delay,
 909	    endTime,
 910	    filterLabels,
 911	    activeNamespace,
 912	    queriesKey,
 913	    samples,
 914	    span,
